83	async function mockEfficacy(
84		page: import('@playwright/test').Page,
85		opts: {
86			compareFn?: (req: Record<string, unknown>) => Record<string, unknown>;
87			rows?: typeof EFFICACY_ROWS;
88		} = {}
89	) {
90		await page.route('/graphql', async (route) => {
91			const body = route.request().postDataJSON() as {
92				query: string;
93				variables?: Record<string, unknown>;
94			};
95			if (body.query.includes('NodeInfo')) {
96				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { nodeInfo: NODE_INFO } }) });
97			} else if (body.query.includes('Projects')) {
98				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } } }) });
99			} else if (body.query.includes('EfficacyRows') || body.query.includes('efficacyRows')) {
100				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { efficacyRows: opts.rows ?? EFFICACY_ROWS } }) });
101			} else if (body.query.includes('EfficacyAttempts') || body.query.includes('efficacyAttempts')) {
102				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { efficacyAttempts: ATTEMPTS_DETAIL } }) });
103			} else if (body.query.includes('ComparisonDispatch') || body.query.includes('comparisonDispatch')) {
104				const result = opts.compareFn
105					? opts.compareFn(body.variables ?? {})
106					: { id: 'cmp-001', state: 'queued' };
107				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { comparisonDispatch: result } }) });
108			} else if (body.query.includes('Comparisons')) {
109				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { comparisons: [] } }) });
110			} else {
111				await route.continue();
112			}
113		});
114	}
