116	test('US-096.a: efficacy table lists every (harness, provider, model) tuple with required columns', async ({ page }) => {
117		await mockEfficacy(page);
118		await page.goto(BASE_URL);
119	
120		const table = page.getByRole('table', { name: /efficacy/i });
121		await expect(table).toBeVisible();
122	
123		// Column headers that MUST be present.
124		for (const header of [/harness/i, /provider/i, /model/i, /attempts/i, /success/i, /tokens/i, /duration/i, /cost/i]) {
125			await expect(table.getByRole('columnheader', { name: header })).toBeVisible();
126		}
127	
128		// One row per tuple.
129		for (const row of EFFICACY_ROWS) {
130			const tr = table.getByRole('row', { name: new RegExp(`${row.harness}.*${row.model}`, 'i') });
131			await expect(tr).toBeVisible();
132			await expect(tr).toContainText(String(row.attempts));
133		}
134	
135		// No-cost-signal case uses em-dash placeholder, not empty or "0".
136		const noCostRow = table.getByRole('row', { name: /qwen3\.6/i });
137		await expect(noCostRow).toContainText('—');
138	});
