33	// BeadClose is the resolver for the beadClose field.
34	func (r *mutationResolver) BeadClose(ctx context.Context, id string, reason *string) (*Bead, error) {
35		if r.WorkingDir == "" {
36			return nil, fmt.Errorf("working directory not configured")
37		}
38		store := r.beadStore()
39		if err := store.Close(id); err != nil {
40			return nil, err
41		}
42		if reason != nil && strings.TrimSpace(*reason) != "" {
43			_ = store.AppendEvent(id, bead.BeadEvent{
44				Kind:    "summary",
45				Summary: "closed: " + strings.TrimSpace(*reason),
46			})
47		}
48		b, err := store.Get(id)
49		if err != nil {
50			return nil, err
51		}
52		return beadModelFromBead(b), nil
53	}
