55	// WorkerDispatch is the resolver for the workerDispatch field.
56	func (r *mutationResolver) WorkerDispatch(ctx context.Context, kind string, projectID string, args *string) (*WorkerDispatchResult, error) {
57		switch kind {
58		case "execute-loop":
59			if r.Actions == nil {
60				return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
61			}
62			return r.Actions.DispatchWorker(ctx, kind, r.projectRoot(projectID), args)
63		case "realign-specs", "run-checks":
64			return &WorkerDispatchResult{
65				ID:    "queued-worker-" + slug(kind),
66				State: queuedPlaceholderState,
67				Kind:  kind,
68			}, nil
69		default:
70			return nil, fmt.Errorf("unsupported worker kind %q", kind)
71		}
72	}
