605	func pluginInfoFromPackage(pkg registry.Package, workingDir string, installed registry.InstalledEntry) *PluginInfo {
606		info := &PluginInfo{
607			Name:           pkg.Name,
608			Version:        pkg.Version,
609			Type:           string(pkg.Type),
610			Description:    pkg.Description,
611			Keywords:       append([]string(nil), pkg.Keywords...),
612			Status:         "available",
613			RegistrySource: pkg.Source,
614			Skills:         []string{},
615			Prompts:        []string{},
616			Templates:      []string{},
617		}
618		if installed.Name != "" {
619			info.InstalledVersion = strPtr(installed.Version)
620			info.Status = "installed"
621			if installed.Version != "" && installed.Version != pkg.Version {
622				info.Status = "update-available"
623			}
624		}
625		if manifest, err := json.Marshal(pkg); err == nil {
626			info.Manifest = strPtr(string(manifest))
627		}
628		enrichPluginInfoFromDisk(info, workingDir, pkg.Name, installed)
629		return info
