649	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, entry registry.InstalledEntry) {
650		for _, root := range pluginRootCandidates(workingDir, name, entry) {
651			if root == "" {
652				continue
653			}
654			if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
655				continue
656			}
657			if info.DiskBytes == 0 {
658				info.DiskBytes = dirSize(root)
659			}
660			if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
661				if pkg.Version != "" {
662					info.Version = pkg.Version
663				}
664				if pkg.Description != "" {
665					info.Description = pkg.Description
666				}
667				if pkg.Type != "" {
668					info.Type = string(pkg.Type)
669				}
670				if pkg.Source != "" {
671					info.RegistrySource = pkg.Source
672				}
673				if len(pkg.Keywords) > 0 {
674					info.Keywords = append([]string(nil), pkg.Keywords...)
675				}
676				if manifest, err := json.Marshal(pkg); err == nil {
677					info.Manifest = strPtr(string(manifest))
678				}
679			}
680			info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
681			info.Prompts = uniqueStrings(append(info.Prompts, scanNamedChildren(root, []string{"prompts", "library/prompts"}, "")...))
682			info.Templates = uniqueStrings(append(info.Templates, scanNamedChildren(root, []string{"templates", "library/templates"}, "")...))
683		}
684	}
