686	func pluginRootCandidates(workingDir string, name string, entry registry.InstalledEntry) []string {
687		var roots []string
688		if workingDir != "" {
689			roots = append(roots, filepath.Join(workingDir, ".ddx", "plugins", name))
690		}
691		roots = append(roots, registry.ExpandHome(filepath.Join("~", ".ddx", "plugins", name)))
692		for _, f := range entry.Files {
693			expanded := registry.ExpandHome(f)
694			if expanded == "" {
695				continue
696			}
697			roots = append(roots, pluginRootFromRecordedFile(expanded, name))
698		}
699		return uniqueStrings(roots)
700	}
701	
702	func pluginRootFromRecordedFile(path string, name string) string {
703		cleaned := filepath.Clean(path)
704		if filepath.Base(cleaned) == name {
705			return cleaned
706		}
707		for dir := cleaned; dir != "." && dir != string(filepath.Separator); dir = filepath.Dir(dir) {
708			if filepath.Base(dir) == name && filepath.Base(filepath.Dir(dir)) == "plugins" {
709				return dir
710			}
711			next := filepath.Dir(dir)
712			if next == dir {
713				break
714			}
715		}
716		return cleaned
717	}
718	
719	func dirSize(root string) int {
720		var total int64
721		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
722			if err != nil || d.IsDir() {
723				return nil
724			}
725			if info, err := d.Info(); err == nil {
726				total += info.Size()
727			}
728			return nil
729		})
730		const maxInt32 = int64(1<<31 - 1)
731		if total > maxInt32 {
732			return int(maxInt32)
733		}
734		return int(total)
735	}
736	
737	func scanNamedChildren(root string, relDirs []string, marker string) []string {
738		var out []string
739		for _, rel := range relDirs {
740			base := filepath.Join(root, filepath.FromSlash(rel))
741			entries, err := os.ReadDir(base)
742			if err != nil {
743				continue
744			}
745			for _, entry := range entries {
746				if strings.HasPrefix(entry.Name(), ".") {
747					continue
748				}
749				if marker != "" {
750					if !entry.IsDir() {
751						continue
752					}
753					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
754						continue
755					}
756				}
757				out = append(out, entry.Name())
758			}
759		}
760		return out
761	}
