852	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
853		if raw == nil || strings.TrimSpace(*raw) == "" {
854			return nil, nil
855		}
856		value := strings.TrimSpace(*raw)
857		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
858			if parsed, err := time.Parse(layout, value); err == nil {
859				utc := parsed.UTC()
860				return &utc, nil
861			}
862		}
863		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
864	}
