1016	func collectPaletteMatches(query string, workingDir string) []paletteMatch {
1017		var out []paletteMatch
1018		if graph, err := docgraph.BuildGraphWithConfig(workingDir); err == nil {
1019			for _, doc := range graph.AllNodesForOutput() {
1020				if score, ok := paletteScore(query, doc.Path, doc.Title); ok {
1021					out = append(out, paletteMatch{
1022						kind:    "document",
1023						id:      filepath.ToSlash(doc.Path),
1024						title:   doc.Title,
1025						score:   score,
1026						sortKey: "document:" + doc.Path,
1027					})
1028				}
1029			}
1030		}
1031	
1032		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
1033		if beads, err := store.ReadAll(); err == nil {
1034			for _, b := range beads {
1035				if score, ok := paletteScore(query, b.ID, b.Title); ok {
1036					out = append(out, paletteMatch{kind: "bead", id: b.ID, title: b.Title, score: score, sortKey: "bead:" + b.ID})
1037				}
1038			}
1039		}
1040	
1041		for _, action := range []struct{ id, label string }{
1042			{"drain-queue", "Drain queue"},
1043			{"realign-specs", "Re-align specs"},
1044			{"run-checks", "Run checks"},
1045		} {
1046			if score, ok := paletteScore(query, action.id, action.label); ok {
1047				out = append(out, paletteMatch{kind: "action", id: action.id, title: action.label, score: score, sortKey: "action:" + action.id})
1048			}
1049		}
1050		for _, nav := range []struct{ route, title string }{
1051			{"/beads", "Beads"},
1052			{"/documents", "Documents"},
1053			{"/graph", "Graph"},
1054			{"/workers", "Workers"},
1055			{"/personas", "Personas"},
1056			{"/plugins", "Plugins"},
1057			{"/efficacy", "Efficacy"},
1058		} {
1059			if score, ok := paletteScore(query, nav.route, nav.title); ok {
1060				out = append(out, paletteMatch{kind: "nav", id: nav.route, title: nav.title, score: score, sortKey: "nav:" + nav.route})
1061			}
1062		}
1063		return out
