267	func measureP95(iterations int, fn func()) time.Duration {
268		durations := make([]time.Duration, iterations)
269		for i := 0; i < iterations; i++ {
270			start := time.Now()
271			fn()
272			durations[i] = time.Since(start)
273		}
274		sort.Slice(durations, func(i, j int) bool { return durations[i] < durations[j] })
275		idx := int(float64(iterations)*0.95+0.999999) - 1
276		if idx < 0 {
277			idx = 0
278		}
279		if idx >= len(durations) {
280			idx = len(durations) - 1
281		}
282		return durations[idx]
283	}
